const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');
const { z } = require('zod');

const app = express();

// --- Security middleware ---
app.use(helmet());
app.use(cors({ origin: process.env.ALLOWED_ORIGIN || false }));
app.use(express.json({ limit: '100kb' }));
app.use(
  rateLimit({
    windowMs: 60_000,
    max: 100,
    standardHeaders: true,
    legacyHeaders: false,
  })
);

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Example of validated query params (e.g., /users?limit=10)
const listUsersQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).optional(),
});

app.get('/users', (req, res, next) => {
  const parsed = listUsersQuery.safeParse(req.query);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid query', details: parsed.error.flatten() });
  }
  const users = [
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]; // consider omitting email unless the caller is authorized
  res.json(parsed.data.limit ? users.slice(0, parsed.data.limit) : users);
});

// --- 404 + error handlers (must be last) ---
app.use((_req, res) => res.status(404).json({ error: 'Not found' }));

// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Log internally; never return err.stack to clients
  console.error({ msg: 'unhandled_error', err: err.message });
  res.status(500).json({ error: 'Internal server error' });
});

// --- Server + graceful shutdown ---
const PORT = Number(process.env.PORT) || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

for (const sig of ['SIGINT', 'SIGTERM']) {
  process.on(sig, () => {
    server.close(() => process.exit(0));
    setTimeout(() => process.exit(1), 10_000).unref(); // force-exit fallback
  });
}

module.exports = app;
```

