  const parsed = IdParam.safeParse(req.params);
  if (!parsed.success) return res.status(400).json({ error: 'bad_request' });
  const { id } = parsed.data;
  // parameterized query: db.query('SELECT ... WHERE id = $1', [id])
  res.json({ id });
});
```

