  res.json([{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }]);
});

app.use((err, req, res, _next) => {
  console.error(err);
  res.status(500).json({ error: 'Internal Server Error' });
});

module.exports = app;
```

---

