app.get('/users', requireAuth, (req, res) => {
  // Only return fields the caller needs; avoid leaking emails to non-admins.
  const isAdmin = req.user.role === 'admin';
  res.json(users.map(u => isAdmin ? u : { id: u.id, name: u.name }));
